css:
.wrapper.sc-reorder-alerts {
    --surface: var(--block-bg-color, #15151A);
    --surface-raised: #1B1B22;
    --ink: var(--color-text, #F4F4F7);
    --muted: var(--color-gray-500, #8A8A96);
    --muted-strong: var(--color-gray-700, #C2C2CC);
    --line: var(--color-gray-200, rgba(255,255,255,.07));
    --hairline: rgba(255,255,255,.06);
    --accent: var(--color-primary, #FFD21E);
    --accent-2: var(--color-secondary, #FF3D8B);
    --danger: var(--color-danger, #FF5A6E);
    --success: var(--color-success, #36D399);
    container-type: inline-size;
    color: var(--ink);
    font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
    display: flex;
    flex-direction: column;
    gap: 14px;
    padding: 2px;
}

/* ---- Header ------------------------------------------------------- */
.wrapper.sc-reorder-alerts .ra-head {
    display: flex;
    align-items: flex-end;
    justify-content: space-between;
    gap: 12px;
    flex-wrap: wrap;
}
.wrapper.sc-reorder-alerts .ra-eyebrow {
    display: flex;
    align-items: center;
    gap: 7px;
    font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui);
    letter-spacing: .13em;
    text-transform: uppercase;
    color: var(--muted-strong);
}
.wrapper.sc-reorder-alerts .ra-eyebrow::before {
    content: "";
    width: 7px;
    height: 7px;
    border-radius: 50%;
    background: var(--accent);
    flex: 0 0 auto;
}
.wrapper.sc-reorder-alerts .ra-title {
    margin: 6px 0 0;
    font: 800 22px/1.15 var(--font-stack-primary, 'Inter', system-ui);
    letter-spacing: -.01em;
    color: var(--ink);
}

/* ---- Alert count chip (the one restrained glow: active/alert) ----- */
.wrapper.sc-reorder-alerts .ra-count {
    font: 800 12px/1 var(--font-stack-primary, 'Inter', system-ui);
    letter-spacing: .02em;
    padding: 9px 14px;
    border-radius: 999px;
    border: 1px solid var(--line);
    color: var(--muted);
    background: color-mix(in srgb, var(--ink) 4%, transparent);
    white-space: nowrap;
    font-variant-numeric: tabular-nums;
}
.wrapper.sc-reorder-alerts .ra-count.is-danger {
    color: var(--danger);
    border-color: color-mix(in srgb, var(--danger) 50%, transparent);
    background: color-mix(in srgb, var(--danger) 13%, transparent);
    box-shadow: 0 0 22px -8px color-mix(in srgb, var(--danger) 60%, transparent);
}
.wrapper.sc-reorder-alerts .ra-count.is-ok {
    color: var(--success);
    border-color: color-mix(in srgb, var(--success) 42%, transparent);
    background: color-mix(in srgb, var(--success) 12%, transparent);
}

/* ---- Data table --------------------------------------------------- */
.wrapper.sc-reorder-alerts .ra-tbl {
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
    border-radius: 14px;
    border: 1px solid var(--line);
    background: var(--surface);
    box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
}
.wrapper.sc-reorder-alerts table {
    width: 100%;
    border-collapse: collapse;
    font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui);
}
.wrapper.sc-reorder-alerts thead th {
    position: sticky;
    top: 0;
    background: var(--surface);
    text-align: left;
    font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui);
    letter-spacing: .04em;
    text-transform: uppercase;
    color: var(--muted);
    padding: 12px 14px;
    border-bottom: 1px solid var(--line);
    white-space: nowrap;
    z-index: 1;
}
.wrapper.sc-reorder-alerts thead th.num { text-align: right; }
.wrapper.sc-reorder-alerts tbody tr { transition: background .15s ease; }
.wrapper.sc-reorder-alerts tbody td {
    padding: 11px 14px;
    border-top: 1px solid var(--hairline);
    color: var(--ink);
    vertical-align: top;
    transition: background .15s ease, box-shadow .15s ease;
}
.wrapper.sc-reorder-alerts td.num {
    text-align: right;
    font-variant-numeric: tabular-nums;
    white-space: nowrap;
}
/* Reorder gap = the per-row hero exception number (semantic danger). */
.wrapper.sc-reorder-alerts td.ra-gap {
    color: var(--danger);
    font-weight: 800;
    background: color-mix(in srgb, var(--danger) 8%, transparent);
}
/* Hover = active row: raise surface + yellow left marker (one accent). */
.wrapper.sc-reorder-alerts tbody tr:hover td { background: var(--surface-raised); }
.wrapper.sc-reorder-alerts tbody tr:hover td:first-child { box-shadow: inset 3px 0 0 var(--accent); }
.wrapper.sc-reorder-alerts tbody tr:hover td.ra-gap { background: color-mix(in srgb, var(--danger) 15%, var(--surface-raised)); }

/* ---- Two-line cells ----------------------------------------------- */
.wrapper.sc-reorder-alerts .ra-twoline .ra-strong { font-weight: 700; color: var(--ink); }
.wrapper.sc-reorder-alerts .ra-sub {
    margin-top: 2px;
    font: 600 11px/1.2 var(--font-stack-primary, 'Inter', system-ui);
    color: var(--muted);
}

/* ---- Status pills (semantic + label, never color alone) ----------- */
.wrapper.sc-reorder-alerts .ra-pill {
    display: inline-block;
    padding: 3px 9px;
    border-radius: 999px;
    font: 700 10.5px/1.3 var(--font-stack-primary, 'Inter', system-ui);
    letter-spacing: .04em;
    text-transform: uppercase;
    border: 1px solid var(--line);
    color: var(--muted);
    background: color-mix(in srgb, var(--ink) 4%, transparent);
    white-space: nowrap;
}
.wrapper.sc-reorder-alerts .ra-pill.is-ok {
    color: var(--success);
    border-color: color-mix(in srgb, var(--success) 42%, transparent);
    background: color-mix(in srgb, var(--success) 12%, transparent);
}
.wrapper.sc-reorder-alerts .ra-pill.is-danger {
    color: var(--danger);
    border-color: color-mix(in srgb, var(--danger) 48%, transparent);
    background: color-mix(in srgb, var(--danger) 12%, transparent);
}
.wrapper.sc-reorder-alerts .ra-pill.is-muted {
    color: var(--muted);
    border-color: var(--line);
}

/* ---- Empty / all-stocked state ------------------------------------ */
.wrapper.sc-reorder-alerts .ra-empty {
    border: 1px solid var(--line);
    border-radius: 14px;
    padding: 30px 18px;
    text-align: center;
    background: var(--surface);
    box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
    color: var(--muted);
    font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui);
}
.wrapper.sc-reorder-alerts .ra-empty-title {
    font: 800 15px/1.2 var(--font-stack-primary, 'Inter', system-ui);
    color: var(--ink);
}
.wrapper.sc-reorder-alerts .ra-empty-title::before {
    content: "";
    display: inline-block;
    width: 8px;
    height: 8px;
    border-radius: 50%;
    margin-right: 8px;
    background: var(--success);
    vertical-align: middle;
}
.wrapper.sc-reorder-alerts .ra-empty-sub {
    margin-top: 6px;
    font: 500 12px/1.4 var(--font-stack-primary, 'Inter', system-ui);
    color: var(--muted);
}

/* ---- Responsive (sizes to the block's own cell) ------------------- */
@container (max-width: 560px) {
    .wrapper.sc-reorder-alerts thead th,
    .wrapper.sc-reorder-alerts tbody td { padding: 9px 10px; }
    .wrapper.sc-reorder-alerts .ra-title { font-size: 19px; }
}
@media (prefers-reduced-motion: reduce) {
    .wrapper.sc-reorder-alerts tbody tr,
    .wrapper.sc-reorder-alerts tbody td { transition: none; }
}
